import React from "react";

function Navbar() {
  return (
    <div
      style={{
        width: "100%",
        height: "65px",
        background: "linear-gradient(90deg, #020617, #0f172a)",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 30px",
        borderBottom: "1px solid rgba(255,255,255,0.08)",
        boxShadow: "0 4px 20px rgba(0,0,0,0.35)"
      }}
    >

      {/* Left Title */}
      <h2
        style={{
          margin: 0,
          fontSize: "20px",
          fontWeight: "600",
          color: "#a78bfa",
          letterSpacing: "0.5px"
        }}
      >
        🚀 PlaceHub
      </h2>

      {/* Right Section */}
      <span
        style={{
          color: "#cbd5f5",
          fontSize: "15px"
        }}
      >
        Placement Analytics Dashboard
      </span>

    </div>
  );
}

export default Navbar;
